A debounce function delays the execution of a function until a certain amount of time has passed without further calls.

```javascript
function debounce(func, delay) {
  let timeout;
  return function(...args) {
    const context = this;
    clearTimeout(timeout);
    timeout = setTimeout(() => func.apply(context, args), delay);
  };
}

// Example Usage:

function search(query) {
  console.log("Searching for:", query);
}

// Create a debounced version of the search function with a 500ms delay
const debouncedSearch = debounce(search, 500);

// Simulate rapid key presses
debouncedSearch("apple");
debouncedSearch("appl");
debouncedSearch("app");
debouncedSearch("appe");
debouncedSearch("appel"); // Only this one will execute after 500ms if no further calls

// After a pause, this will execute
setTimeout(() => {
  debouncedSearch("banana");
}, 1000);
```
